const allDivs=document.querySelectorAll(".event-card-wrap div:not(.wrap)");cards=Array.from(allDivs),cards.forEach((function(element){element.addEventListener("click",(function(e){if(!e.target.closest("a")){let parent=element;for(;parent&&!parent.querySelector("a");)parent=parent.parentElement;const link=parent?.querySelector("a");link&&link.click()}}))}));